241	
242	  it("non-owner cannot delete someone else's comment (403)", async () => {
243	    const res = await request(app)
244	      .delete(`/comments/${commentId}`)
245	      .set("Authorization", `Bearer ${otherToken}`);
246	    expect(res.status).toBe(403);
247	  });
248	
249	  it("owner can delete their own comment", async () => {
250	    const res = await request(app)
251	      .delete(`/comments/${commentId}`)
252	      .set("Authorization", `Bearer ${userToken}`);
253	    expect(res.status).toBe(200);
254	  });
255	});
